use std::collections::HashMap;

struct DnsCache {
    cache: HashMap<String, String>,
}

impl DnsCache {
    fn new() -> Self {
        DnsCache { cache: HashMap::new() }
    }

    fn set_record(&mut self, name: &str, ip: &str) {
        let key = format!("{}", name);
        self.cache.insert(key, ip.to_string());
    }

    fn get_cached_ip(&self, name: &str) -> Option<&String> {
        self.cache.get(name)
    }
}

fn main() {
    let mut cache = DnsCache::new();
    cache.set_record("example.com", "192.0.2.1");

    if let Some(ip) = cache.get_cached_ip("google.internal") {
        println!("Found IP for google.internal: {}", ip);
    } else {
        let message = format!("No record found for google.internal in the local cache.");
        println!("{}", message);
    }

    let name_to_check = "example.com";
    if let Some(ip) = cache.get_cached_ip(name_to_check) {
        let formatted_output = format!("Successfully resolved {} to IP address {}", name_to_check, ip);
        println!("{}", formatted_output);
    } else {
        let error_message = format!("Could not resolve {} during lookup.", name_to_check);
        println!("{}", error_message);
    }
}

use std::fmt::Write;

struct Photo {
    exif_date: String,
    filename: String,
}

fn format_photo_name(photos: Vec<Photo>) -> Result<Vec<String>, Box<dyn std::error::Error>> {
    let mut formatted_names = Vec::new();
    for photo in photos {
        let mut buffer = String::new();
        writeln!(buffer, "{}", photo.exif_date)?; 
        let date_part = photo.exif_date;
        let name_part = &photo.filename;

        let formatted_name = format!("{}_{}", date_part, name_part);
        formatted_names.push(formatted_name);
    }
    Ok(formatted_names)
}

fn main() {
    let photos = vec![ 
        Photo { exif_date: "2023-10-25".to_string(), filename: "vacation_a.jpg".to_string() },
        Photo { exif_date: "2024-01-15".to_string(), filename: "event_b.png".to_string() }
    ];

    match format_photo_name(photos) {
        Ok(names) => {
            println!("Successfully formatted names:");
            for name in names {
                println!("{}", name);
            }
        },
        Err(e) => {
            eprintln!("An error occurred: {}", e);
        }
    }
}

use std::fmt::Write;

struct SensorData {
    id: u32,
    temperature: f32,
    humidity: f32,
}

impl ToString for SensorData {
    fn to_string(&self) -> String {
        let mut buffer = String::new();
        writeln!(buffer, "Device ID: {}", self.id).unwrap();
        write!(buffer, "Temperature: {:.1}C", self.temperature).unwrap();
        write!(buffer, "Humidity: {:.1}%", self.humidity).unwrap();
        buffer
    }
}

fn main() {
    let data = SensorData { 
        id: 42,
        temperature: 23.567,
        humidity: 60.12,
    };
    println!("{}", data.to_string());
}
